INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("クローチェ", 1, 0.0, "いらっしゃいませっ♪\nキャラバンコインを使って\n買い物ができますよっ！", 126401, 1.47, 1, "2023/06/30 12:00:00", 2, 1, 10001, -470.0, "2023/09/22 14:59:59", 2002);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("クローチェ", 1, 0.0, "素敵な品が揃ってるので\nたーっくさん買っていって\nくださいねっ♪", 126401, 2.15, 2, "2023/06/30 12:00:00", 1, 2, 10002, -470.0, "2023/09/22 14:59:59", 2002);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("ライラエル", 1, 0.0, "ショップへようこそ\nキャラバンコインはこちら\nで買い物に使えますよ", 126501, 0.0, 2, "2023/06/30 12:00:00", 2, 1, 10003, -470.0, "2023/09/22 14:59:59", 2002);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("ライラエル", 1, 0.0, "こちらのショップで\n買い物をして、素敵な\n旅を楽しんでくださいね", 126501, 0.0, 1, "2023/06/30 12:00:00", 1, 2, 10004, -470.0, "2023/09/22 14:59:59", 2002);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("リンド", 2, 0.0, "いらっしゃいませ\nキャラバンコインを使って\nお買い物ができますよ", 127702, 0.0, 2, "2023/09/15 15:00:00", 2, 1, 10005, -470.0, "2023/12/22 14:59:59", 2002);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("リンド", 2, 0.0, "ショップの掃除は完璧です\n姫さま直営のお店として\n当然のことですから", 127702, 0.0, 2, "2023/09/15 15:00:00", 2, 2, 10006, -470.0, "2023/12/22 14:59:59", 2002);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("ヴルム", 2, 0.0, "ショップへようこそ\nキャラバンコインと品物を\n交換できるんで、よければ", 127802, 0.0, 1, "2023/09/15 15:00:00", 1, 1, 10007, -470.0, "2023/12/22 14:59:59", 2002);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("ヴルム", 2, 0.0, "なんで店番なんか…\nま、やりますけど\n好きな品物をどうぞ", 127802, 6.5, 2, "2023/09/15 15:00:00", 1, 2, 10008, -470.0, "2023/12/22 14:59:59", 2002);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("アネモネ", 3, 0.0, "──いらっしゃいませ\n買い物しても、いいですよ\nキャラバンコインがあれば", 129602, 0.0, 2, "2023/12/15 15:00:00", 1, 1, 10009, -470.0, "2024/03/22 14:59:59", 2002);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("アネモネ", 3, 0.0, "──もっと笑顔がほしい？\nいくらコインを積まれても\n売れない物はありますから", 129602, 0.0, 2, "2023/12/15 15:00:00", 1, 2, 10010, -470.0, "2024/03/22 14:59:59", 2002);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("ネフィ=ネラ", 3, 0.0, "ようこそおいでなんし\nキャラバンコインをこちら\nで交換して進ぜんしょう", 129701, 0.0, 1, "2023/12/15 15:00:00", 1, 1, 10011, -470.0, "2024/03/22 14:59:59", 2002);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("ネフィ=ネラ", 3, 0.0, "ところで、お前さまは\nいくらで贖えるのか喃？\n──フフ、冗談でありんす", 129701, 6.2, 2, "2023/12/15 15:00:00", 1, 2, 10012, -470.0, "2024/03/22 14:59:59", 2002);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("カノン", 4, 0.0, "い、いらっしゃいませっ！\n…くっ…このあたくし様が\n店番なんて…屈辱ですわっ", 130301, 3.1, 3, "2024/03/15 15:00:00", 5, 1, 10013, -470.0, "2024/06/22 14:59:59", 2002);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("カノン", 4, 0.0, "あら、あたくしをご所望？\nお生憎様、そんな小銭では\n…買えちゃうんですの！？", 130301, 6.15, 3, "2024/03/15 15:00:00", 2, 2, 10014, -470.0, "2024/06/22 14:59:59", 2002);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("ナーナ", 4, 0.0, "いらっしゃいませ～♪\nきゃらばんこいん？を\n交換できるんだってー", 130401, 0.0, 2, "2024/03/15 15:00:00", 2, 1, 10015, -470.0, "2024/06/22 14:59:59", 2002);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("ナーナ", 4, 0.0, "甘いのくれたら、\nお礼にナーナの拾った\n松ぼっくりあげちゃうよ！", 130401, 3.35, 2, "2024/03/15 15:00:00", 1, 2, 10016, -470.0, "2024/06/22 14:59:59", 2002);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("ホウオウ", 5, 0.0, "ショップへようこそ\nこの鳳凰が、皆さんに\n祝福を差し上げましょう", 130502, 0.0, 1, "2024/06/15 15:00:00", 1, 1, 10017, -470.0, "2024/09/22 14:59:59", 2002);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("ホウオウ", 5, 0.0, "ほーちゃんと呼ぶ権利は\n売っていませんよ？\n騎士さんへの、特別です！", 130502, 3.18, 2, "2024/06/15 15:00:00", 1, 2, 10018, -470.0, "2024/09/22 14:59:59", 2002);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("ホウオウ", 5, 0.0, "うﾞぇぇえんっ！まﾞだごの\n格好になっぢゃいまじだ！\n寄付をお願いじまず～っ！", 130503, 0.0, 4, "2024/06/15 15:00:00", 4, 3, 10019, -470.0, "2024/09/22 14:59:59", 2002);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("ネア", 5, 0.0, "おっすー♪\nなんでも交換してけー\nカリザきゅん以外で", 123301, 4.9, 1, "2024/06/15 15:00:00", 2, 1, 10020, -470.0, "2024/09/22 14:59:59", 2002);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("ネア", 5, 0.0, "ところで、騎士きゅんは\nおいくら万ルピ？\nジョーダンぬ・き・で♡", 123301, 4.8, 1, "2024/06/15 15:00:00", 2, 2, 10021, -470.0, "2024/09/22 14:59:59", 2002);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("カリザ", 6, 0.0, "ケッ、なんでオレ様が店番\nなんざ…って来んなキイロ\nオレは売りモンじゃねー！", 133301, 4.922, 3, "2024/09/15 15:00:00", 1, 1, 10022, -470.0, "2024/12/22 14:59:59", 2002);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("カリザ", 6, 0.0, "い、言わなきゃダメか？\n「…いらっしゃいませ…」\nクソッ、笑うんじゃねー！", 133301, 9.638, 3, "2024/09/15 15:00:00", 5, 2, 10023, -470.0, "2024/12/22 14:59:59", 2002);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("ミーア", 6, 0.0, "ショップへようこそ～\nネラさまの腹心…的な私が\n店番させていただきま～す", 133401, 2.88, 1, "2024/09/15 15:00:00", 2, 1, 10024, -470.0, "2024/12/22 14:59:59", 2002);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("ミーア", 6, 0.0, "私の抜け殻とか、\n需要ありますかね～…\nって冗談ですよ、冗談！", 133401, 4.818, 5, "2024/09/15 15:00:00", 1, 2, 10025, -470.0, "2024/12/22 14:59:59", 2002);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("グレイス", 7, 0.0, "へい、らっしゃい\nさ、騎士氏。冥土の土産は\nなにがいいですか？", 133002, 1.78, 2, "2024/12/15 15:00:00", 1, 1, 10026, -470.0, "2025/03/22 14:59:59", 2002);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("グレイス", 7, 0.0, "商品をお買い上げ毎に\nグレイスちゃんポイントを\n差し上げます。嘘ですが", 133002, 6.15, 1, "2024/12/15 15:00:00", 7, 2, 10027, -470.0, "2025/03/22 14:59:59", 2002);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("ヴァイオレット", 7, 0.0, "ようこそいらっしゃいませ\n…接客とは、このような\n振舞で宜しいでしょうか？", 133102, 4.28, 6, "2024/12/15 15:00:00", 2, 1, 10028, -470.0, "2025/03/22 14:59:59", 2002);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("ヴァイオレット", 7, 0.0, "じめじめした商品は\nございませんので\n安心してお買い求め下さい", 133102, 0.0, 1, "2024/12/15 15:00:00", 1, 2, 10029, -470.0, "2025/03/22 14:59:59", 2002);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("ルルィ", 8, 0.0, "いらっしゃいましぇでしゅ\n何をお求めでしゅか？\nたこ焼きもありましゅよ！", 136902, 5.53, 2, "2025/03/15 15:00:00", 1, 1, 10030, -470.0, "2025/06/23 14:59:59", 2002);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("ルルィ", 8, 0.0, "そのコイン…ピカピカで、\n集めたくなっちゃいましゅ\nタコ釣られされちゃう～…", 136902, 6.05, 9, "2025/03/15 15:00:00", 7, 2, 10031, -470.0, "2025/06/23 14:59:59", 2002);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("デュラン", 8, 0.0, "姫のご友人ならば\n礼儀を尽くすのが爺の務め\nさ、望みの物を言いたまえ", 137001, 0.0, 2, "2025/03/15 15:00:00", 1, 1, 10032, -470.0, "2025/06/23 14:59:59", 2002);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("デュラン", 8, 0.0, "キャラバンコインではなく\n首で支払って貰えんかのぅ\n…冗談であるぞ？", 137001, 0.0, 2, "2025/03/15 15:00:00", 1, 2, 10033, -470.0, "2025/06/23 14:59:59", 2002);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("サツキ", 9, 0.0, "おう\n好きなもん持ってきな", 135902, 0.0, 2, "2025/06/16 15:00:00", 2, 1, 10034, -470.0, "2025/09/23 14:59:59", 2002);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("サツキ", 9, 0.0, "宵越しの銭を持つような\n野暮いマネぁしくさんな\nツキが落ちてもしらねぇぜ", 135902, 4.935, 1, "2025/06/16 15:00:00", 6, 2, 10035, -470.0, "2025/09/23 14:59:59", 2002);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("ユキノ", 9, 0.0, "ら、ら、らっしゃっせ…\nなんかほしいもん、ある？\nか、かき氷とか、ど…？", 135802, 7.441, 2, "2025/06/16 15:00:00", 5, 1, 10036, -470.0, "2025/09/23 14:59:59", 2002);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("ユキノ", 9, 0.0, "そ、そんな見ねぇで…\nあては、売りもんじゃ\nねぇよ…？", 135802, 0.0, 7, "2025/06/16 15:00:00", 7, 2, 10037, -470.0, "2025/09/23 14:59:59", 2002);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("クルル", 10, 0.0, "クルルをお求めですかっ？\nそれならお礼に、こちらの\n宝石もどうぞですよ～♪", 130901, 2.295, 2, "2025/09/16 15:00:00", 2, 1, 10038, -470.0, "2025/12/22 14:59:59", 2002);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("クルル", 10, 0.0, "はっ！　ヒーローさんから\nお代なんて頂けないです！\nどうぞどうぞ…え、ダメ？", 130901, 6.281, 1, "2025/09/16 15:00:00", 6, 2, 10039, -470.0, "2025/12/22 14:59:59", 2002);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("ヴォルガーノ", 10, 0.0, "よぅ！　今日の俺さまは\n門番じゃなく、店番だぜ\nメモピ～スフィア～てな！", 137701, 5.549, 2, "2025/09/16 15:00:00", 1, 1, 10040, -470.0, "2025/12/22 14:59:59", 2002);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("ヴォルガーノ", 10, 0.0, "…リマさんのブロマイド？\n買い取るに決まってらぁ！\nなんでも持ってけ泥棒っ！", 137701, 2.64, 3, "2025/09/16 15:00:00", 6, 2, 10041, -470.0, "2025/12/22 14:59:59", 2002);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("ライラエル", 11, 0.0, "こ、この格好は…ヴルムが\n集客効果があると言って…\n…本当でしょうか？", 132801, 7.642, 7, "2025/12/15 15:00:00", 4, 1, 10042, -470.0, "2026/03/23 11:59:59", 2002);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("ライラエル", 11, 0.0, "この我に店番させるとは…\n全て買わねば許さぬぞ\n我が国庫に貢献するが良い", 132802, 0.0, 1, "2025/12/15 15:00:00", 1, 2, 10043, -470.0, "2026/03/23 11:59:59", 2002);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("クローチェ", 11, 0.0, "アナライズっ！\n本日のオススメ商品は～…\nこちらですっ♪", 134502, 0.0, 1, "2025/12/15 15:00:00", 1, 1, 10044, -470.0, "2026/03/23 11:59:59", 2002);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("クローチェ", 11, 0.0, "ギガンティックローチェ、\nおひとついかがですかっ？\n格納庫用意して下さいねっ", 134501, 3.72, 2, "2025/12/15 15:00:00", 1, 2, 10045, -470.0, "2026/03/23 11:59:59", 2002);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("ネフィ＝ネラ", 12, 0.0, "番頭も、飯事の如き営み\nなれば。愛らしき稚児らで\n千客万来といきませぬか喃", 138201, 4.991, 2, "2026/03/16 12:00:00", 1, 1, 10046, -470.0, "2026/06/22 11:59:59", 2002);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("ネフィ＝ネラ", 12, 0.0, "国を営むに金子は必須也…\nどうか御恵みくだしゃんせ\n誠心を以て報恩致しまする", 138201, 3.877, 1, "2026/03/16 12:00:00", 4, 2, 10047, -470.0, "2026/06/22 11:59:59", 2002);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("アラクネ", 12, 0.0, "あぅっ…！　天井が低くて\n頭をぶつけてしまって…\nわたしが、大きいだけ…？", 136001, 1.71, 4, "2026/03/16 12:00:00", 6, 1, 10048, -470.0, "2026/06/22 11:59:59", 2002);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("アラクネ", 12, 0.0, "いらっしゃいませ騎士さま\nくつろいでいって下さいね\nもし叶うなら…永遠に…", 136001, 5.32, 5, "2026/03/16 12:00:00", 2, 2, 10049, -470.0, "2026/06/22 11:59:59", 2002);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("アネモネ", 13, 0.0, "水着で、店番とか──\n本当、意味がわかりません\n海の家でもないのに…", 135401, 3.727, 9, "2026/06/15 12:00:00", 4, 1, 10050, -470.0, "2026/09/22 11:59:59", 2002);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("アネモネ", 13, 0.0, "──リアみたいに、\nもっと愛想良い接客を…\nいえ──なんでもないです", 135401, 7.213, 7, "2026/06/15 12:00:00", 9, 2, 10051, -470.0, "2026/09/22 11:59:59", 2002);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("クリア", 13, 0.0, "いらっしゃいませー♪\n奉仕活動兼、将来のために\nたくさん働いちゃいます♪", 135301, 1.874, 1, "2026/06/15 12:00:00", 2, 1, 10052, -470.0, "2026/09/22 11:59:59", 2002);
INSERT INTO `v1_b17694c024cc797abaface41b984ce8979a18c1aa920d4f027865ca805989c3a` VALUES ("クリア", 13, 0.0, "アルバイトが終わったら\n海に遊びに行きましょう！\nモネちゃんも一緒に♪", 135301, 0.0, 2, "2026/06/15 12:00:00", 2, 2, 10053, -470.0, "2026/09/22 11:59:59", 2002);
